import{_ as t,O as r,H as o,f as l,k as n,i}from"./chunks/framework.Pt2pSV98.js";const L=JSON.parse('{"title":"大语言模型 (LLM)","description":"用海量文本训练、能理解和生成人类语言的深度学习模型","frontmatter":{"title":"大语言模型 (LLM)","description":"用海量文本训练、能理解和生成人类语言的深度学习模型","difficulty":"beginner"},"headers":[],"relativePath":"terms/llm.md","filePath":"terms/llm.md"}'),s={name:"terms/llm.md"};function h(d,e,u,m,g,c){const a=r("DifficultyBadge");return o(),l("div",null,[n(a,{level:"beginner"}),e[0]||(e[0]=i('<h1 id="大语言模型-llm" tabindex="-1">大语言模型 (LLM) <a class="header-anchor" href="#大语言模型-llm" aria-label="Permalink to &quot;大语言模型 (LLM)&quot;">​</a></h1><p>LLM（Large Language Model）是当前 AI 浪潮的核心驱动力。简单说，它是一个<strong>在海量文本上训练出来的超级语言预测器</strong>。</p><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>LLM 是用数十亿到数万亿参数训练出来、能理解上下文并生成连贯文本的深度学习模型。ChatGPT、Claude、DeepSeek 和通义千问都是 LLM。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>想象一个<strong>读过整个互联网的超级学霸</strong>——他几乎读过人类公开的所有书籍、文章、论坛帖子和代码。你问他任何问题，他都能基于&quot;读过的内容&quot;给出回答。他不会真正&quot;思考&quot;，但他的知识面广到惊人，并且能模仿人类的表达方式。</p><p>他的 &quot;阅读量&quot; 有多大？GPT-4 的训练数据大约相当于 <strong>几百万本《三体》</strong> 的文字量。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>LLM 的核心架构是 <strong>Transformer</strong>（2017 年 Google 提出），它通过自注意力机制理解文本中词与词之间的远距离依赖关系。训练过程分为两个阶段：</p><ol><li><strong>预训练（Pre-training）</strong>：在互联网规模的文本上学习语言模式和世界知识</li><li><strong>对齐（Alignment）</strong>：通过 RLHF 等方法让模型输出符合人类偏好</li></ol><p>训练一次顶级 LLM 的成本可达 <strong>数千万到数亿美元</strong>，需要数千张 GPU 运行数月。</p><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/ai-ml-dl.html">AI / ML / DL</a> —— LLM 属于深度学习的一种</li><li><a href="/ai-knowledge/terms/token.html">Token</a> —— LLM 处理文本的基本单位</li><li><a href="/ai-knowledge/terms/context-window.html">上下文窗口</a> —— LLM 一次能 &quot;记住&quot; 多少内容</li><li><a href="/ai-knowledge/terms/fine-tuning.html">微调 (Fine-tuning)</a> —— 让 LLM 适应特定任务</li></ul><h2 id="快速记忆" tabindex="-1">快速记忆 <a class="header-anchor" href="#快速记忆" aria-label="Permalink to &quot;快速记忆&quot;">​</a></h2><p>把 LLM 想象成读完了整个中文互联网的超级学霸——它不一定&quot;知道&quot;答案，但知道怎么&quot;组织&quot;答案。</p><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2303.08774" target="_blank" rel="noreferrer">OpenAI GPT-4 技术报告</a></li><li><a href="https://arxiv.org/abs/1706.03762" target="_blank" rel="noreferrer">Attention Is All You Need</a> —— Transformer 原始论文</li><li><a href="https://www.youtube.com/watch?v=zjkBMFhNj_g" target="_blank" rel="noreferrer">Andrej Karpathy: Intro to LLMs</a> —— 1 小时视频全面介绍</li></ul>',17))])}const p=t(s,[["render",h]]);export{L as __pageData,p as default};
